#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e6 + 5;
int nxt[MAXN][26], flag[MAXN], cnt = 0, pointer; //trie
int n, m;
string s;
void Insert(string s)//trie__insert
{
	int p = 0;
	for (auto c : s)
	{
		if (!nxt[p][c - 'a'])
		{
			nxt[p][c - 'a'] = ++cnt;
		}
		p = nxt[p][c - 'a'];
	}
	flag[p] = true;
}
int Find(string s)//trie__find
{
	int p = 0;
	for (auto c : s)
	{
		if (!nxt[p][c - 'a'])
		{
			return false;
		}
		p = nxt[p][c - 'a'];
	}
	pointer = p;
	return flag[p];
}
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	n = read();
	for (int i = 1; i <= n; ++i)
	{
		cin >> s;
		Insert(s);
	}
	m = read();
	for (int i = 1; i <= m; ++i)
	{
		cin >> s;
		if (Find(s) == false)puts("WRONG");
		else if (Find(s) == true)
		{
			puts("OK");
			flag[pointer] = 2;
		}
		else if (Find(s) == 2)
		{
			puts("REPEAT");
		}
	}
	return false;
}
